11. using Azure.ResourceManager;
12. 
13. namespace Azure.ResourceManager
14. {
15.     /// <summary>
16.     /// A class representing Azure resource manager client options.
17.     /// </summary>
18. #pragma warning disable AZC0008 // ClientOptions should have a nested enum called ServiceVersion
19.     public sealed class ArmClientOptions : ClientOptions
20. #pragma warning restore AZC0008 // ClientOptions should have a nested enum called ServiceVersion
21.     {
22.         internal IDictionary<ResourceType, string> ResourceApiVersionOverrides { get; } = new Dictionary<ResourceType, string>();
23. 
24.         /// <summary>
25.         /// Gets or sets Azure cloud environment.
26.         /// </summary>
27.         public ArmEnvironment? Environment { get; set; }
28. 
29.         /// <summary>
30.         /// Sets the api version to use for a given resource type.
31.         /// To find which API Versions are available in your environment you can use the <see cref="ResourceProviderResource.Get"/> method
32.         /// for the provider namespace you are interested in.
33.         /// </summary>
34.         /// <param name="resourceType"> The resource type to set the version for. To determine the appropriate value, you can refer to the corresponding documentation or XML documentation comments of the API. Then, get its resource type from the Resource's ResourceType field.</param>
35.         /// <param name="apiVersion"> The api version to use. </param>
36.         public void SetApiVersion(ResourceType resourceType, string apiVersion)
37.         {
38.             Argument.AssertNotNullOrEmpty(apiVersion, nameof(apiVersion));
39. 
40.             ResourceApiVersionOverrides[resourceType] = apiVersion;
41.         }
42. 
43.         /// <summary>
44.         /// Sets the api versions from an Azure Stack profile.
45.         /// </summary>
46.         public void SetApiVersionsFromProfile(AzureStackProfile profile)
47.         {
48.             var assembly = Assembly.GetExecutingAssembly();
49.             using (Stream stream = assembly.GetManifestResourceStream(profile.GetManifestName()))
50.             {
51.                 var span = BinaryData.FromStream(stream).ToMemory().Span;
52.                 var allProfile = JsonSerializer.Deserialize<Dictionary<string, Dictionary<string, JsonElement>>>(span);
53.                 var armProfile = allProfile["resource-manager"];
54.                 foreach (var keyValuePair in armProfile)
55.                 {
56.                     var namespaceName = keyValuePair.Key;
57.                     var element = keyValuePair.Value;
58. 
59.                     foreach (var apiVersionProperty in element.EnumerateObject())
60.                     {
61.                         var apiVersion = apiVersionProperty.Name;
62.                         foreach (var resourceTypeItem in apiVersionProperty.Value.EnumerateArray())
63.                         {
64.                             string resourceTypeName = default;
65.                             foreach (var property in resourceTypeItem.EnumerateObject())
66.                             {
67.                                 if (property.NameEquals("resourceType"))
68.                                 {
69.                                     resourceTypeName = property.Value.GetString();
70.                                     break;
71.                                 }
